"use client";

import { useState, useEffect } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";
import { format } from "date-fns";
import { fr } from "date-fns/locale";
import { Calendar as CalendarIcon, Clock, Plus, Search } from "lucide-react";
import { cn } from "@/lib/utils";
import { createClient } from "@/lib/supabase/client";
import { toast } from "sonner";

interface Patient {
  id: string;
  first_name: string;
  last_name: string;
  patient_number: string;
}

export function NewAppointmentForm({
  onAppointmentCreated,
}: {
  onAppointmentCreated?: () => void;
}) {
  const [isOpen, setIsOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const supabase = createClient();

  // Form State
  const [date, setDate] = useState<Date>();
  const [time, setTime] = useState("09:00");
  const [duration, setDuration] = useState("30");
  const [notes, setNotes] = useState("");

  // Patient Selection State
  const [patients, setPatients] = useState<Patient[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  // Search patients
  useEffect(() => {
    const searchPatients = async () => {
      if (searchQuery.length < 2) {
        setPatients([]);
        return;
      }
      setIsSearching(true);
      const { data, error } = await supabase
        .from("patients")
        .select("id, first_name, last_name, patient_number")
        .or(
          `first_name.ilike.%${searchQuery}%,last_name.ilike.%${searchQuery}%,patient_number.ilike.%${searchQuery}%`,
        )
        .limit(5);

      if (!error && data) {
        setPatients(data);
      }
      setIsSearching(false);
    };

    const debounce = setTimeout(searchPatients, 300);
    return () => clearTimeout(debounce);
  }, [searchQuery, supabase]);

  const handleSubmit = async () => {
    if (!selectedPatient || !date || !time) {
      toast.error(
        "Veuillez remplir tous les champs obligatoires (Patient, Date, Heure).",
      );
      return;
    }

    setIsSubmitting(true);

    // Combine Date and Time
    const [hours, minutes] = time.split(":");
    const appointmentDate = new Date(date);
    appointmentDate.setHours(parseInt(hours), parseInt(minutes), 0, 0);

    try {
      const { error } = await supabase.from("appointments").insert({
        patient_id: selectedPatient.id,
        appointment_date: appointmentDate.toISOString(),
        duration_minutes: parseInt(duration),
        notes,
        status: "scheduled",
      });

      if (error) throw error;

      toast.success("Rendez-vous créé avec succès.");
      setIsOpen(false);

      // Reset form
      setSelectedPatient(null);
      setSearchQuery("");
      setDate(undefined);
      setTime("09:00");
      setDuration("30");
      setNotes("");

      if (onAppointmentCreated) {
        onAppointmentCreated();
      }
    } catch (error: unknown) {
      toast.error("Erreur lors de la création du rendez-vous.");
      const errMsg = error instanceof Error ? error.message : "Erreur inconnue";
      console.error(errMsg);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={setIsOpen}>
      <DialogTrigger>
        <div className="inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 bg-primary text-primary-foreground hover:bg-primary/90 h-10 px-4 py-2 cursor-pointer">
          <Plus className="w-4 h-4 mr-2" />
          Nouveau Rendez-vous
        </div>
      </DialogTrigger>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle>Planifier un rendez-vous</DialogTitle>
          <DialogDescription>
            Recherchez un patient et définissez la date et l&apos;heure de la
            consultation.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-4">
          {/* Patient Selection */}
          <div className="space-y-2 relative">
            <Label>
              Patient <span className="text-red-500">*</span>
            </Label>
            {selectedPatient ? (
              <div className="flex items-center justify-between p-2 border rounded-md bg-slate-50">
                <span className="font-medium">
                  {selectedPatient.first_name} {selectedPatient.last_name} (
                  {selectedPatient.patient_number})
                </span>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedPatient(null)}
                  className="h-6 px-2 text-xs"
                >
                  Changer
                </Button>
              </div>
            ) : (
              <div>
                <div className="relative">
                  <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder="Rechercher par nom, prénom ou N° patient..."
                    className="pl-9"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                {searchQuery.length >= 2 && (
                  <div className="absolute top-16 w-full bg-white border rounded-md shadow-lg z-10 max-h-[200px] overflow-auto">
                    {isSearching ? (
                      <div className="p-3 text-sm text-muted-foreground text-center">
                        Recherche...
                      </div>
                    ) : patients.length === 0 ? (
                      <div className="p-3 text-sm text-muted-foreground text-center">
                        Aucun patient trouvé.
                      </div>
                    ) : (
                      patients.map((p) => (
                        <div
                          key={p.id}
                          className="flex items-center justify-between p-2 hover:bg-slate-100 cursor-pointer text-sm"
                          onClick={() => {
                            setSelectedPatient(p);
                            setSearchQuery("");
                            setPatients([]);
                          }}
                        >
                          <span>
                            {p.first_name} {p.last_name}
                          </span>
                          <span className="text-muted-foreground text-xs">
                            {p.patient_number}
                          </span>
                        </div>
                      ))
                    )}
                  </div>
                )}
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            {/* Date Selection */}
            <div className="space-y-2 flex flex-col">
              <Label>
                Date <span className="text-red-500">*</span>
              </Label>
              <Popover>
                <PopoverTrigger>
                  <div
                    tabIndex={0}
                    role="button"
                    className={cn(
                      "flex w-full items-center justify-start text-left font-normal border rounded-md px-3 py-2 text-sm",
                      !date && "text-muted-foreground",
                    )}
                  >
                    <CalendarIcon className="mr-2 h-4 w-4" />
                    {date ? (
                      format(date, "PPP", { locale: fr })
                    ) : (
                      <span>Choisir une date</span>
                    )}
                  </div>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <Calendar
                    mode="single"
                    selected={date}
                    onSelect={setDate}
                    initialFocus
                    locale={fr}
                  />
                </PopoverContent>
              </Popover>
            </div>

            {/* Time Selection */}
            <div className="space-y-2">
              <Label>
                Heure <span className="text-red-500">*</span>
              </Label>
              <div className="flex relative">
                <Clock className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                  type="time"
                  className="pl-9"
                  value={time}
                  onChange={(e) => setTime(e.target.value)}
                  required
                />
              </div>
            </div>
          </div>

          {/* Duration */}
          <div className="space-y-2">
            <Label>Durée estimée (minutes)</Label>
            <Input
              type="number"
              value={duration}
              onChange={(e) => setDuration(e.target.value)}
              min="15"
              step="15"
            />
          </div>

          {/* Notes */}
          <div className="space-y-2">
            <Label>Motif / Notes</Label>
            <Textarea
              placeholder="Ex: Première consultation, Détartrage..."
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
            />
          </div>
        </div>

        <div className="flex justify-end gap-2">
          <Button
            variant="outline"
            onClick={() => setIsOpen(false)}
            disabled={isSubmitting}
          >
            Annuler
          </Button>
          <Button
            onClick={handleSubmit}
            disabled={isSubmitting || !selectedPatient || !date || !time}
          >
            {isSubmitting ? "Création..." : "Confirmer le RDV"}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}
